import java.util.Arrays;

public class KruskalMST {
    // Storage: Edge structure representation
    public static class Edge implements Comparable<Edge> {
        int src, dest, weight;
        public int compareTo(Edge other) {
            return this.weight - other.weight; // Process sorting metric
        } 
    }

    // Process: Kruskal's algorithm
    public static void findMST(Edge[] edges, int verticesCount) {
        // Process: Sort edges in ascending order of weights
        Arrays.sort(edges);

        // Storage: Disjoint Set parent array
        int[] parent = new int[verticesCount];
        for (int i = 0; i < verticesCount; i++) parent[i] = i;

        int mstEdges = 0;
        int mstWeight = 0;

        for (Edge edge : edges) {
            int rootSrc = findParent(edge.src, parent);
            int rootDest = findParent(edge.dest, parent);

            // Process: Union-find check to prevent cycles
            if (rootSrc != rootDest) {
                System.out.println("Edge in MST: " + edge.src + " -- " + edge.dest + " == " + edge.weight); // Output
                mstWeight += edge.weight;
                parent[rootSrc] = rootDest; // Union
                mstEdges++;
                if (mstEdges == verticesCount - 1) break;
            }
        }
    }

    private static int findParent(int node, int[] parent) {
        if (parent[node] == node) return node;
        return parent[node] = findParent(parent[node], parent); // Path compression
    }
}

import java.util.Arrays;

public class PrimMST {
    public static void findMST(int[][] graph, int V) {
        // Input: adjacency matrix graph and vertices count V

        // Storage: parent, key, and MST state
        int[] parent = new int[V];
        int[] key = new int[V];
        boolean[] mstSet = new boolean[V];

        Arrays.fill(key, Integer.MAX_VALUE);
        key[0] = 0; // Source vertex key is 0
        parent[0] = -1;

        // Process: find MST edges
        for (int count = 0; count < V - 1; count++) {
            int u = minKey(key, mstSet, V); // Storage: active vertex
            mstSet[u] = true;

            // Update key values of adjacent vertices
            for (int v = 0; v < V; v++) {
                if (graph[u][v] != 0 && !mstSet[v] && graph[u][v] < key[v]) {
                    parent[v] = u;
                    key[v] = graph[u][v];
                }
            }
        }

        // Output: print MST edges
        for (int i = 1; i < V; i++) {
            System.out.println(parent[i] + " - " + i + "\t" + graph[i][parent[i]]);
        }
    }

    private static int minKey(int[] key, boolean[] mstSet, int V) {
        int min = Integer.MAX_VALUE, min_index = -1;
        for (int v = 0; v < V; v++) {
            if (!mstSet[v] && key[v] < min) {
                min = key[v];
                min_index = v;
            }
        }
        return min_index;
    }
}

