import java.util.ArrayList;

public class DirectedCycleDetector {
    public static boolean hasCycle(int V, ArrayList<ArrayList<Integer>> adj) {
        // Input: vertices V and Adjacency list adj

        // Storage: Visited and Recursion Stack trackers
        boolean[] visited = new boolean[V];
        boolean[] recStack = new boolean[V];

        // Process: Loop all vertices to handle disjoint segments
        for (int i = 0; i < V; i++) {
            if (dfs(i, adj, visited, recStack)) {
                return true; // Output: Cycle found
            }
        }
        return false; // Output: Safe
    }

    private static boolean dfs(int u, ArrayList<ArrayList<Integer>> adj, boolean[] visited, boolean[] recStack) {
        if (recStack[u]) return true; // Found back-edge!
        if (visited[u]) return false;

        visited[u] = true;
        recStack[u] = true;

        for (int v : adj.get(u)) {
            if (dfs(v, adj, visited, recStack)) return true;
        }

        recStack[u] = false; // backtrack
        return false;
    }
}
